WITH apple_ship AS (SELECT SUM(s.product_gms) AS total_sales, SUM(s.shipped_cogs) AS total_cogs FROM shipped_raw s WHERE s.brand_name IS NOT NULL AND s.brand_name ILIKE '%Apple%'), apple_ret AS (SELECT COALESCE(SUM(c.ncrc), 0) AS total_ncrc FROM concession_raw c WHERE c.brand_name IS NOT NULL AND c.brand_name ILIKE '%Apple%'), samsung_ship AS (SELECT SUM(s.product_gms) AS total_sales, SUM(s.shipped_cogs) AS total_cogs FROM shipped_raw s WHERE s.brand_name IS NOT NULL AND s.brand_name ILIKE '%Samsung%'), samsung_ret AS (SELECT COALESCE(SUM(c.ncrc), 0) AS total_ncrc FROM concession_raw c WHERE c.brand_name IS NOT NULL AND c.brand_name ILIKE '%Samsung%') SELECT 'Apple' AS brand_group, sh.total_sales, sh.total_cogs, r.total_ncrc, sh.total_sales - sh.total_cogs - r.total_ncrc AS net_margin FROM apple_ship sh CROSS JOIN apple_ret r UNION ALL SELECT 'Samsung' AS brand_group, sh.total_sales, sh.total_cogs, r.total_ncrc, sh.total_sales - sh.total_cogs - r.total_ncrc AS net_margin FROM samsung_ship sh CROSS JOIN samsung_ret r;